  'Using base knowledge'::text as agent_response,
  'no_results'::text as outcome,
  NULL as category,
  NULL as step,
  999::float8 as similarity_score,
  2 as priority
WHERE NOT EXISTS (SELECT 1 FROM search_results)
ORDER BY priority, similarity_score;
`;

